// Simple IPFS helper stubs so the app can run
// without requiring any external IPFS service.

// Return false so the app knows not to treat stored
// values as IPFS CIDs.
export function hasIPFSSupport() {
	return false;
}

// Called by addNote/updateNote. Returning null tells
// the caller to fall back to storing the encrypted
// note content directly on-chain.
export async function uploadTextToIPFS(text) {
	return null;
}

// Not used when hasIPFSSupport() is false, but we
// provide it for completeness.
export async function fetchTextFromIPFS(cid) {
	return "";
}
